+/* ===========================================================================
+ * makeIcon / makeActionButton — decorative glyphs hidden from assistive tech
+ *
+ * Bootstrap Icons paint their glyph via a CSS `::before { content: '\f...' }`
+ * rule, and some screen readers announce generated content / private-use-area
+ * code points as stray noise. Every glyph produced by `makeIcon` is paired
+ * with a visible text label (the menu item's label), so the glyph is purely
+ * decorative and MUST be hidden from the accessibility tree via
+ * `aria-hidden="true"` (WCAG 1.3.1). `makeIcon` is the central builder for
+ * every menu-item glyph, so hiding it there covers all menu icons at once.
+ * ========================================================================= */
+describe('makeIcon — decorative glyph hidden from assistive tech (WCAG 1.3.1)', () => {
+  // The full set of icon names passed to makeIcon across the browse view's
+  // row menus (Download/Upload/Delete/Move/Copy) and the dir menu
+  // (Upload/New directory). Each must be hidden from AT.
+  it.each(['upload', 'download', 'trash', 'arrows-move', 'files', 'folder-plus'])(
+    'sets aria-hidden="true" on the bi-%s glyph',
+    (name) => {
+      expect(makeIcon(name).getAttribute('aria-hidden')).toBe('true');
+    },
+  );
+
+  it('hides the glyph for an arbitrary icon name not special-cased above', () => {
+    expect(makeIcon('house').getAttribute('aria-hidden')).toBe('true');
+  });
+});
+
+describe('makeActionButton — icon hidden from assistive tech (WCAG 1.3.1)', () => {
+  it('the prepended icon glyph carries aria-hidden="true"', () => {
+    const btn = makeActionButton('Delete', () => undefined, 'trash');
+    const icon = btn.firstElementChild as HTMLElement;
+    expect(icon.getAttribute('aria-hidden')).toBe('true');
+  });
+});
+
